 using System.ComponentModel;
 using System.Text.Json;
 using Microsoft.Extensions.Logging;
 using ModelContextProtocol.Server;

 [McpServerToolType]
 public class WeatherApiTools(HttpClient httpClient, ILogger<WeatherApiTools> logger)
 {
     private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

     [McpServerTool, Description("Get the current weather forecast for a US location using latitude and longitude.")]
     public async Task<string> GetForecast(
         [Description("Latitude of the location (e.g. 39.7456)")] double latitude,
         [Description("Longitude of the location (e.g. -97.0892)")] double longitude,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Fetching forecast for ({Lat}, {Lon})", latitude, longitude);

         // Step 1: Resolve the grid point from coordinates
         var pointUrl = $"/points/{latitude},{longitude}";
         using var pointResponse = await httpClient.GetAsync(pointUrl, cancellationToken);
         pointResponse.EnsureSuccessStatusCode();

         var pointDoc = await JsonDocument.ParseAsync(
             await pointResponse.Content.ReadAsStreamAsync(cancellationToken), cancellationToken: cancellationToken);
         var forecastUrl = pointDoc.RootElement.GetProperty("properties").GetProperty("forecast").GetString()
             ?? throw new InvalidOperationException("Forecast URL not found in point response.");

         // Step 2: Fetch the forecast
         using var forecastResponse = await httpClient.GetAsync(forecastUrl, cancellationToken);
         forecastResponse.EnsureSuccessStatusCode();

         var forecastDoc = await JsonDocument.ParseAsync(
             await forecastResponse.Content.ReadAsStreamAsync(cancellationToken), cancellationToken: cancellationToken);
         var periods = forecastDoc.RootElement.GetProperty("properties").GetProperty("periods");

         // Return the first 3 forecast periods as formatted JSON
         var results = periods.EnumerateArray().Take(3).Select(p => new
         {
             Name = p.GetProperty("name").GetString(),
             Temperature = $"{p.GetProperty("temperature").GetInt32()}°{p.GetProperty("temperatureUnit").GetString()}",
             Forecast = p.GetProperty("detailedForecast").GetString()
         });

         return JsonSerializer.Serialize(results, JsonOptions);
     }

     [McpServerTool, Description("Get active weather alerts for a US state.")]
     public async Task<string> GetAlerts(
         [Description("Two-letter US state code (e.g. CA, NY, TX)")] string state,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Fetching alerts for state {State}", state);

         var url = $"/alerts/active?area={state.ToUpperInvariant()}";
         using var response = await httpClient.GetAsync(url, cancellationToken);
         response.EnsureSuccessStatusCode();

         var doc = await JsonDocument.ParseAsync(
             await response.Content.ReadAsStreamAsync(cancellationToken), cancellationToken: cancellationToken);
         var features = doc.RootElement.GetProperty("features");

         if (features.GetArrayLength() == 0)
             return $"No active alerts for {state.ToUpperInvariant()}.";

         var alerts = features.EnumerateArray().Take(5).Select(f =>
         {
             var props = f.GetProperty("properties");
             return new
             {
                 Event = props.GetProperty("event").GetString(),
                 Severity = props.GetProperty("severity").GetString(),
                 Headline = props.GetProperty("headline").GetString()
             };
         });

         return JsonSerializer.Serialize(alerts, JsonOptions);
     }
 }
